import { LayoutDashboard, GraduationCap, Microscope, Calculator, BookOpen, Atom } from "lucide-react";

export default function Home() {
    const subjects = [
        { name: "Math", icon: <Calculator className="w-6 h-6" />, color: "from-blue-500 to-cyan-500" },
        { name: "Physics", icon: <Atom className="w-6 h-6" />, color: "from-purple-500 to-indigo-500" },
        { name: "Biology", icon: <Microscope className="w-6 h-6" />, color: "from-green-500 to-emerald-500" },
        { name: "Chemistry", icon: <Atom className="w-6 h-6" />, color: "from-yellow-500 to-orange-500" },
        { name: "English", icon: <BookOpen className="w-6 h-6" />, color: "from-pink-500 to-rose-500" },
    ];

    return (
        <main className="min-height-screen p-8 md:p-24 flex flex-col items-center">
            <div className="max-w-5xl w-full flex flex-col gap-12">
                {/* Header Section */}
                <section className="text-center space-y-4">
                    <h1 className="text-5xl md:text-7xl font-bold tracking-tight text-gradient">
                        SmartPath AI
                    </h1>
                    <p className="text-xl text-white/60 max-w-2xl mx-auto">
                        Your personalized AI-driven learning companion. Master your subjects with dynamic paths and expert guidance.
                    </p>
                </section>

                {/* Dashboard Preview / Subjects */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {subjects.map((subject) => (
                        <div
                            key={subject.name}
                            className="glass-card p-6 flex items-center gap-4 group cursor-pointer"
                        >
                            <div className={`p-3 rounded-xl bg-gradient-to-br ${subject.color} group-hover:scale-110 transition-transform`}>
                                {subject.icon}
                            </div>
                            <div>
                                <h3 className="text-xl font-semibold">{subject.name}</h3>
                                <p className="text-sm text-white/40">Diagnostic ready</p>
                            </div>
                        </div>
                    ))}

                    <div className="glass-panel p-6 flex flex-col justify-center items-center gap-2 border-dashed border-white/20 hover:border-brand-primary/50 transition-colors cursor-pointer lg:col-span-1">
                        <LayoutDashboard className="w-8 h-8 text-white/20" />
                        <span className="text-white/40 font-medium">Coming Soon</span>
                    </div>
                </div>

                {/* Call to Action */}
                <div className="glass-panel p-12 text-center space-y-6 bg-brand-primary/5">
                    <GraduationCap className="w-16 h-16 mx-auto text-brand-primary mb-4" />
                    <h2 className="text-3xl font-bold">Start Your Diagnostic Assessment</h2>
                    <p className="text-white/60">
                        Let our AI understand your strengths and weaknesses to build your perfect study roadmap.
                    </p>
                    <button className="px-8 py-3 bg-brand-primary hover:bg-brand-primary/80 text-white font-semibold rounded-full shadow-lg shadow-brand-primary/20 transition-all">
                        Begin Now
                    </button>
                </div>
            </div>
        </main>
    );
}
